import { NextResponse } from 'next/server';
import { adminAuth, adminDb, setCustomUserClaims } from '@/lib/firebaseAdmin';

/**
 * AD-HOC UTILITY: Synchronizes Firebase Custom Claims with Firestore Roles
 * This is meant to be run once to fix administrators who cannot see the System Users tab.
 */
export async function GET() {
    console.log('Starting custom claims synchronization...');
    const results: any[] = [];

    try {
        const usersSnapshot = await adminDb.collection('M_Users').get();

        for (const doc of usersSnapshot.docs) {
            const userData = doc.data();
            const email = userData.Email;
            const role = userData.Role;
            const uid = doc.id;

            console.log(`Processing user: ${email} (${role})...`);

            try {
                // Verify user exists in Auth
                const authUser = await adminAuth.getUser(uid);

                // Set custom claims
                await setCustomUserClaims(uid, role);

                results.push({
                    email,
                    role,
                    status: 'success',
                    claims: {
                        administrator: role === 'Administrator',
                        role: role
                    }
                });
            } catch (authError: any) {
                console.error(`Error processing Auth for ${email}:`, authError.message);
                results.push({
                    email,
                    role,
                    status: 'failed',
                    error: authError.message
                });
            }
        }

        return NextResponse.json({
            success: true,
            processedCount: results.length,
            details: results
        });

    } catch (error: any) {
        console.error('Core synchronization error:', error);
        return NextResponse.json({
            success: false,
            error: error.message
        }, { status: 500 });
    }
}
